// // This module implements a 16-bit wide custom counter with load and reset functionality. When the clock signal's negative edge is detected, the counter will reset to zero if the reset input is high. If the load input is high, it will load the value from `loadValue`. The counter decrements on every clock cycle, and upon reaching its minimum value (all bits low), it wraps around to all ones. Additionally, a flag output indicates when the counter has reached its minimum value.
module top_module(
   input         clock, reset, load,
   input [15:0]  loadValue,
   output [15:0] count,
   output        flag);reg [15:0]    countReg = 16'b0;
   wire          flagWire;

   assign flag = flagWire;
   assign count = countReg;

   always @ (posedge clock) begin 
      if (reset)
         countReg <= 16'b0;
      else if (load)
         countReg <= loadValue;
      else if (countReg == {16{1'b1}})
         countReg <= 16'b0;
      else
         countReg <= countReg + 1;
   end

   assign flagWire = (countReg == {16{1'b1}});

endmodule
